import { useState, useMemo, useCallback } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const ago = (ts) => {
  if (!ts) return "--";
  const d = Date.now() - new Date(ts).getTime();
  if (d < 60000) return `${Math.floor(d / 1000)}s ago`;
  if (d < 3600000) return `${Math.floor(d / 60000)}m ago`;
  return `${Math.floor(d / 3600000)}h ago`;
};

/* ── pipeline config ─────────────────────────────────── */
const STAGES = ["backtest", "review", "staging", "production"];
const STAGE_COLORS = { backtest: "blue", review: "amber", staging: "amber", production: "green" };
const STAGE_LABELS = { backtest: "Backtest", review: "Review", staging: "Staging", production: "Production" };

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Deploy() {
  const { state, toast } = useAppStore();
  const [localOverrides, setLocalOverrides] = useState({});

  /* poll strategies from API to populate the pipeline */
  const fetchStrategies = useCallback(async () => {
    const r = await http.get("/strategies");
    return r.data;
  }, []);
  const { data: strategiesData } = usePoll(fetchStrategies, { intervalMs: 30000, enabled: !state.offlineMode });

  /* Derive pipeline strategies from API catalogue */
  const strategies = useMemo(() => {
    if (!strategiesData) return [];
    const list = strategiesData.strategies ?? (Array.isArray(strategiesData) ? strategiesData : []);
    return list.filter(s => s.status === "active" || s.promotion_status).map(s => {
      const name = s.label || s.key || s.name;
      const apiStage = s.promotion_status === "approved" ? "production"
        : s.promotion_action === "promote" && s.promotion_status === "pending" ? "review"
        : "backtest";
      return {
        name,
        stage: localOverrides[name] ?? apiStage,
        ts: null,
        version: "1.0",
        status: "healthy",
      };
    });
  }, [strategiesData, localOverrides]);

  /* poll backtest + approvals */
  const { data: btData } = usePoll(
    async () => { const r = await http.get("/backtest/status"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );
  const { data: approvals } = usePoll(
    async () => { const r = await http.get("/control/approvals"); return Array.isArray(r.data) ? r.data : []; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* derived stats */
  const deployed  = strategies.filter(s => s.stage === "production").length;
  const inStaging = strategies.filter(s => s.stage === "staging").length;
  const inReview  = strategies.filter(s => s.stage === "review").length;
  const failedDeploys = 0;

  /* pipeline buckets */
  const buckets = useMemo(() => {
    const b = { backtest: [], review: [], staging: [], production: [] };
    strategies.forEach(s => { if (b[s.stage]) b[s.stage].push(s); });
    return b;
  }, [strategies]);

  /* derive deployment history from strategies */
  const deployHistory = useMemo(() => {
    return strategies
      .filter(s => s.ts)
      .sort((a, b) => new Date(b.ts) - new Date(a.ts))
      .map(s => ({
        strategy: s.name,
        version: s.version || "--",
        stage: s.stage,
        by: s.deployedBy || "--",
        ts: s.ts,
        status: s.status === "healthy" ? "success" : s.status === "failed" ? "failed" : "success",
      }));
  }, [strategies]);

  /* actions */
  const promote = (name, from) => {
    const idx = STAGES.indexOf(from);
    if (idx < 0 || idx >= STAGES.length - 1) return;
    const next = STAGES[idx + 1];
    setLocalOverrides(prev => ({ ...prev, [name]: next }));
    toast(`${name} promoted to ${STAGE_LABELS[next]}`, "info");
  };

  const rollback = (name) => {
    setLocalOverrides(prev => ({ ...prev, [name]: "staging" }));
    toast(`${name} rolled back to Staging`, "warn");
  };

  const statusColor = (s) => s === "success" ? "green" : s === "failed" ? "red" : s === "rolled_back" ? "amber" : "blue";

  return (
    <>
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Deployment Pipeline</h1>
          <div className="v2-muted">Strategy promotion: backtest, review, staging, production.</div>
        </div>
      </div>

      {/* top stats */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Deployed Strategies" value={strategies.length > 0 ? deployed : "--"} t="green" sub="Live in production" />
        <Stat label="In Staging" value={strategies.length > 0 ? inStaging : "--"} t="amber" sub="Awaiting promotion" />
        <Stat label="Pending Review" value={strategies.length > 0 ? inReview : "--"} t="blue" sub="Under evaluation" />
        <Stat label="Failed Deploys" value={strategies.length > 0 ? failedDeploys : "--"} t={failedDeploys > 0 ? "red" : "green"} sub="Last 7 days" />
      </div>

      {/* pipeline visualization */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Pipeline Stages</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginTop: 8 }}>
            {STAGES.map((stage, i) => (
              <div key={stage} style={{ position: "relative" }}>
                <div style={{
                  padding: "10px 12px",
                  borderRadius: 10,
                  border: `1px solid var(--v2-${STAGE_COLORS[stage]})`,
                  background: `rgba(${stage === "production" ? "110,240,180" : stage === "backtest" ? "150,190,255" : "255,210,120"},0.06)`,
                  minHeight: 80,
                }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: `var(--v2-${STAGE_COLORS[stage]})`, marginBottom: 8 }}>
                    {STAGE_LABELS[stage]} ({buckets[stage].length})
                  </div>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                    {buckets[stage].map(s => (
                      <span key={s.name} className="v2-pill" style={{
                        borderColor: `var(--v2-${STAGE_COLORS[stage]})`,
                        fontSize: 11,
                        cursor: stage !== "production" ? "pointer" : "default",
                      }}
                        onClick={() => stage !== "production" && promote(s.name, stage)}
                        title={stage !== "production" ? `Click to promote to ${STAGE_LABELS[STAGES[STAGES.indexOf(stage) + 1]]}` : "Live"}
                      >
                        {s.name}
                      </span>
                    ))}
                  </div>
                </div>
                {i < STAGES.length - 1 && (
                  <div style={{ position: "absolute", right: -18, top: "50%", transform: "translateY(-50%)", fontSize: 16, opacity: 0.3 }}>
                    &rarr;
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* deployment history */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Deployment History</div>
          {deployHistory.length === 0 ? (
            <V2EmptyState title="No Deployment History" message="Deployments will appear here once strategies are promoted through the pipeline." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "180px 80px 110px 80px 140px 100px" }}>
                <span>Strategy</span>
                <span>Version</span>
                <span>Stage</span>
                <span>By</span>
                <span>Timestamp</span>
                <span>Status</span>
              </div>
              {deployHistory.map((d, i) => (
                <div key={i} className="v2-tr" style={{ gridTemplateColumns: "180px 80px 110px 80px 140px 100px" }}>
                  <span>{d.strategy}</span>
                  <span className="v2-mono">{d.version}</span>
                  <span className={`v2-${STAGE_COLORS[d.stage] || "blue"}`}>{STAGE_LABELS[d.stage] || d.stage}</span>
                  <span>{d.by}</span>
                  <span className="v2-mono v2-muted">{ago(d.ts)}</span>
                  <span className={`v2-${statusColor(d.status)}`} style={{ fontWeight: 600 }}>
                    {d.status.toUpperCase().replace("_", " ")}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* active deployments + rollback */}
      <div className="v2-grid">
        <div className="v2-card half">
          <div className="v2-ct">Active Deployments</div>
          {buckets.production.length === 0 ? (
            <div className="v2-muted">No strategies in production.</div>
          ) : (
            buckets.production.map(s => (
              <div key={s.name} style={{
                display: "flex", justifyContent: "space-between", alignItems: "center",
                padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.06)"
              }}>
                <div>
                  <span style={{ fontWeight: 600 }}>{s.name}</span>
                  <span className="v2-mono v2-muted" style={{ marginLeft: 8 }}>v{s.version}</span>
                </div>
                <div className="v2-row">
                  <span style={{
                    width: 8, height: 8, borderRadius: "50%",
                    background: s.status === "healthy" ? "var(--v2-green)" : "var(--v2-amber)",
                    display: "inline-block",
                  }} />
                  <span className={`v2-${s.status === "healthy" ? "green" : "amber"}`} style={{ fontSize: 13 }}>
                    {(s.status || "unknown").toUpperCase()}
                  </span>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Rollback Controls</div>
          {buckets.production.length === 0 ? (
            <div className="v2-muted">No active deployments to roll back.</div>
          ) : (
            buckets.production.map(s => (
              <div key={s.name} style={{
                display: "flex", justifyContent: "space-between", alignItems: "center",
                padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.06)"
              }}>
                <div>
                  <span style={{ fontWeight: 600 }}>{s.name}</span>
                  <span className="v2-mono v2-muted" style={{ marginLeft: 8 }}>{ago(s.ts)}</span>
                </div>
                <button className="v2-btn danger" style={{ fontSize: 11, padding: "6px 10px" }} onClick={() => rollback(s.name)}>
                  Rollback
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </>
  );
}
